function [ttl,lbl,outT] = fMapLblV01()% return labels for map analysis%%% Function Label Maker, ver.2% Kei Nakamura% Created on Wednesday, January 12th 2011.% Modified on%% ver.2: %% bodyttl{1} = 'Input beam size';ttl{2} = 'x phase space';ttl{3} = 'y phase space';ttl{4} = 'phase space(x:red,y:green)';ttl{5} = 'Beam size on screen';ttl{6} = 'Energy axis';ttl{7} = 'Beam size factor (x: red, y: blue)';ttl{8} = 'Momentum resolution';ttl{9} = 'Momentum error';lbl{1} = 'x[mm]';lbl{2} = 'y[mm]';lbl{3} = 'xp[mrad]';lbl{4} = 'yp[mrad]';lbl{5} = 'screen[mm]';lbl{6} = 'factor';lbl{7} = 'Momentum[MeV/c]';lbl{8} = 'x size rms [mm]';lbl{9} = 'y size rms [mm]';lbl{10} = 'conv. factor';lbl{11} = 'resolution [%]';lbl{12} = 'x,y (rms) [mm]';lbl{13} = 'momentum error [%]';outT{1} = 'screen[mm]';outT{2} = 'x[mm](rms)';outT{3} = 'xp[mm](rms)';outT{4} = 'y[mm](rms)';outT{5} = 'yp[mm](rms)';outT{6} = 'x[mm](rms,b)';outT{7} = 'xp[mm](rms,b)';outT{8} = 'y[mm](rms,b)';outT{9} = 'yp[mm](rms,b)';outT{10} = 'x conversion fct';outT{11} = 'y conversion fct';outT{12} = 'momentum rsl [%/mrad(FWHM)]';
